chrome.runtime.onInstalled.addListener(()=>{chrome.contextMenus.create({id:"image-to-prompt",title:"🎨 ImageToPrompt - 分析图片",contexts:["image"]})});chrome.contextMenus.onClicked.addListener(async(e,r)=>{if(e.menuItemId==="image-to-prompt"&&e.srcUrl&&(r!=null&&r.id)){await chrome.storage.local.set({currentImageUrl:e.srcUrl,pendingImage:!0}),chrome.sidePanel&&await chrome.sidePanel.open({windowId:r.windowId});try{chrome.tabs.sendMessage(r.id,{type:"FETCH_IMAGE_BASE64",url:e.srcUrl})}catch(n){console.warn("Could not send to content script:",n)}}});chrome.runtime.onMessage.addListener((e,r,n)=>(e.type==="IMAGE_BASE64_READY"&&(chrome.storage.local.set({currentImageBase64:e.base64,currentImageUrl:e.url,pendingImage:!0}),chrome.runtime.sendMessage({type:"IMAGE_SELECTED",url:e.url,base64:e.base64}).catch(()=>{}),n({ok:!0})),!0));chrome.action.onClicked.addListener(e=>{chrome.sidePanel&&e.windowId&&chrome.sidePanel.open({windowId:e.windowId})});
